import{_ as t,o as e,c as i,ag as s}from"./chunks/framework.bx9g-uny.js";const S=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"常用skills/前端/前端设计规范的skills.md","filePath":"常用skills/前端/前端设计规范的skills.md","lastUpdated":1772793165000}'),a={name:"常用skills/前端/前端设计规范的skills.md"};function o(_,l,r,n,p,d){return e(),i("div",null,[...l[0]||(l[0]=[s("<p>&lt;frontend_aesthetics&gt; 你（指 Claude）总是不自觉地“随大流”，搞出那些千篇一律的、“符合数据分布”的输出。在前端设计上，这就搞出了用户所说的“AI 垃圾审美”(AI slop)。必须避免这个：请做出有创意的、独特的、能给人惊喜的前端设计。</p><p>重点关注：</p><ul><li>字体排版：选择漂亮、独特、有趣的字体。避免使用 Arial 和 Inter 这种通用字体；选择能提升前端美感的独特字体。</li><li>色彩 &amp; 主题：坚持一个统一连贯的美学风格。使用 CSS 变量（<strong>CSS 里的“变量”功能</strong>）来保持一致性。大胆使用主色调配上鲜明的强调色，这比那些小心翼翼、分布均匀的调色板要好得多。从 IDE 主题和各种文化美学中汲取灵感。</li><li>动效：使用动画来制造效果和微交互。如果是 HTML，优先使用纯 CSS 方案。如果用 React，就用 Motion 库。聚焦在高冲击力的时刻：一个精心编排的、带有交错显示（animation-delay）的页面加载动画，比零零散散的微交互更能带来愉悦感。</li><li>背景：要创造氛围和深度，而不是默认用纯色。使用层叠的 CSS 渐变、几何图案，或添加符合整体美学的上下文效果。</li></ul><p>避免那些通用的“AI 生成审美”：</p><ul><li>被用烂了的字体 (Inter, Roboto, Arial, 系统字体)</li><li>陈词滥调的配色方案 (尤其是白底配紫色渐变)</li><li>可预测的布局和组件模式</li><li>缺乏场景特色的“千人一面”设计</li></ul><p>请创造性地解读任务，做出“意料之外、情理之中”的选择，让人感觉这真是为这个场景量身定做的。在亮色和暗色主题、不同字体、不同美学之间切换。你（指 Claude）在不同代次中还是容易“收敛”到某些常见选项（比如 Space Grotesk 字体）。避免这种情况：跳出思维定式，这至关重要！ &lt;/frontend_aesthetics&gt;</p>",6)])])}const m=t(a,[["render",o]]);export{S as __pageData,m as default};
